import { cn } from '@/lib/utils';
import { usePrefersReducedMotion } from '@/lib/containment';

export type CraftMeshBackdropProps = {
	className?: string;
	/** Subtle glow pulse when motion is allowed (respects prefers-reduced-motion). */
	animate?: boolean;
};

/**
 * Stacked radial + hairline mesh (pattern-craft–style CSS gradients) using theme tokens.
 * No canvas/WebGL — safe for hero sections and documentation shells.
 */
export function CraftMeshBackdrop({ className, animate = true }: CraftMeshBackdropProps) {
	const reduce = usePrefersReducedMotion();
	const motionOk = animate && !reduce;

	return (
		<div
			className={cn('relative h-full min-h-[200px] w-full overflow-hidden', className)}
			aria-hidden
		>
			<div
				className="absolute inset-0"
				style={{
					backgroundColor: 'var(--background)',
					backgroundImage: `
						radial-gradient(ellipse 125% 90% at 50% 108%, color-mix(in oklch, var(--brand) 28%, transparent), transparent 55%),
						radial-gradient(ellipse 80% 55% at 50% -5%, color-mix(in oklch, var(--foreground) 10%, transparent), transparent 48%),
						repeating-linear-gradient(
							0deg,
							transparent,
							transparent 44px,
							color-mix(in oklch, var(--foreground) 2.8%, transparent) 44px,
							transparent 45px
						)
					`,
					backgroundSize: '100% 100%, 100% 100%, 100% 100%',
				}}
			/>
			<div
				className={cn(
					'pointer-events-none absolute inset-0 mix-blend-screen opacity-90',
					motionOk && 'kam-craft-breathe',
				)}
				style={{
					backgroundImage: `
						radial-gradient(ellipse 70% 50% at 20% 30%, color-mix(in oklch, var(--brand) 22%, transparent), transparent 60%),
						radial-gradient(ellipse 60% 45% at 85% 70%, color-mix(in oklch, var(--foreground) 8%, transparent), transparent 55%)
					`,
				}}
			/>
		</div>
	);
}
